mapper.select:
SELECT * FROM( SELECT TBT.TRUST_NO, CASE WHEN TBH.ID IS NULL THEN TBT.COMPANY_NAME ELSE TBCI.COMPANY_NAME END COMPANY_NAME, CASE WHEN TBH.ID IS NULL THEN TBT.COMPANY_ID ELSE TBCI.COMPANY_ID END COMPANY_ID, TBCI.CARGO_INFO_NO, TBH.ID, TBH.TYPE, DECODE(TBCI.IS_CLEAR,'0','否','1','是','否') IS_CLEAR, TBH.CARGO_INFO_ID, TBT.ID TRUST_ID, TBH.TRUST_CARGO_ID, TBH.SHIPVOYAGE_ID, TBH.SHIPVOYAGE_ITEM_ID, CASE WHEN TBH.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBH.SHIP_NAME) || '_' || TO_CHAR(TBH.VOYAGE) ELSE '' END SHIP_NAME_VOYAGE, CASE WHEN TBH.ID IS NULL THEN TBH.SHIP_NAME ELSE TDS.SHIP_NAME END SHIP_NAME, TDSI.VOYAGE, CASE WHEN TBH.ID IS NULL THEN TBCI.TRADE_TYPE ELSE TBH.TRADE_TYPE END TRADE_TYPE, MDD_TRADE_TYPE.DICT_LABEL TRADE_TYPE_LABEL, CASE WHEN TBH.ID IS NULL THEN TDSI.LOAD_UNLOAD ELSE TBH.LOAD_UNLOAD END LOAD_UNLOAD, CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_ID ELSE TBH.CARGO_OWNER_ID END CARGO_OWNER_ID, CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_NAME ELSE TBH.CARGO_OWNER_NAME END CARGO_OWNER_NAME, TBH.CARGO_AGENT_ID, TBH.CARGO_AGENT_NAME, TBH.CARGO_CODE,
CASE WHEN TBH.ID IS NULL THEN CASE WHEN MC.SIGN IS NOT NULL THEN TBCI.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBCI.CARGO_NAME END ELSE CASE WHEN MC.SIGN IS NOT NULL THEN TBH.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBH.CARGO_NAME END END AS CARGO_NAME, TBH.QUANTITY, TBH.TON, TBH.TICKET_NUM, TBH.STATEMENT_STATUS_CODE, TBH.STATEMENT_STATUS_NAME, TBH.REMARK, TBH.CREATE_BY, TBH.CREATE_BY_NAME, TBH.CREATE_TIME, TBH.UPDATE_BY, TBH.UPDATE_BY_NAME, TBH.UPDATE_TIME, MDD_IN_OUT_TYPE.DICT_LABEL IMP_EXP_LABEL, TDS.LEAVE_BERTH_TIME, TDSI.IMP_EXP, TDS.SCN, TDS.LEAVE_PORT_TIME, TDS.BERTH_TIME, CASE WHEN TDS.LEAVE_PORT_TIME IS NOT NULL THEN '1' ELSE '2' END "isLeave", CASE WHEN TBH.ID IS NULL THEN DECODE (TBCI.PACKING_NAME,'件', '件杂','散' ,'散杂','') ELSE DECODE(MC.WORK_TYPE, '1', '件杂','2' ,'散杂','3','木材','') END workType FROM
T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = TBTC.CARGO_INFO_ID LEFT JOIN T_BUS_HANDOVERLIST TBH ON (TBT.ID = TBH.TRUST_ID and TBH.CARGO_INFO_ID = TBCI.ID) LEFT JOIN M_DICT_DATA MDD_TRADE_TYPE ON (MDD_TRADE_TYPE.DICT_TYPE = 'TRADE_TYPE' AND MDD_TRADE_TYPE.STATUS = '1' AND TBH.TRADE_TYPE = MDD_TRADE_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBH.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND MDD_IN_OUT_TYPE.STATUS = '1' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBH.SHIPVOYAGE_ID = TDS.ID LEFT JOIN M_CARGO MC ON TBCI.CARGO_CODE = MC.CARGO_CODE
T_BUS_HANDOVERLIST TBH LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBH.CARGO_INFO_ID = TBCI.ID LEFT JOIN M_DICT_DATA MDD_TRADE_TYPE ON (MDD_TRADE_TYPE.DICT_TYPE = 'TRADE_TYPE' AND MDD_TRADE_TYPE.STATUS = '1' AND TBH.TRADE_TYPE = MDD_TRADE_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBH.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND MDD_IN_OUT_TYPE.STATUS = '1' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE) LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBH.SHIPVOYAGE_ID = TDS.ID LEFT JOIN M_CARGO MC ON TBH.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON TBH.TRUST_ID = TBT.ID
TBT.STATUS NOT IN ( '10', '20' ) AND TBT.TRUST_TYPE = '2' AND TBT.TYPE = '陆销'
AND TBH.TYPE = #{type, jdbcType=VARCHAR}
AND CASE WHEN TBH.ID IS NULL THEN TBT.COMPANY_ID ELSE TBCI.COMPANY_ID END = #{companyId,jdbcType=BIGINT}
AND TBH.SHIP_NAME LIKE #{shipName_like}
AND TBH.VOYAGE LIKE #{voyage_like}
AND TBH.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND TBH.SHIP_NAME LIKE #{shipName_like, jdbcType=VARCHAR}
AND CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_ID ELSE TBH.CARGO_OWNER_ID END = #{cargoOwnerId, jdbcType=BIGINT}
AND TBH.STATEMENT_STATUS_CODE = #{statementStatusCode, jdbcType=VARCHAR}
AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.SCN LIKE #{scn_like, jdbcType=VARCHAR}
AND case when TBH.ID IS NULL THEN TBCI.CARGO_NAME ELSE TBH.CARGO_NAME END LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
AND TBH.STATEMENT_STATUS_CODE = #{statementStatusCode, jdbcType=VARCHAR}
AND MC.WORK_TYPE = #{workType,jdbcType=VARCHAR}
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
)
AND "isLeave" = #{isLeave,jdbcType=VARCHAR}
ORDER BY LEAVE_PORT_TIME DESC

mapper.update:
UPDATE T_BUS_HANDOVERLIST
SET STATEMENT_STATUS_CODE = #{statementStatusCode,jdbcType=VARCHAR},
    STATEMENT_STATUS_NAME = #{statementStatusName,jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=BIGINT}

mapper.delete:
DELETE
FROM T_COST_STATEMENT
WHERE ID = #{id, jdbcType=BIGINT}

DELETE
FROM T_COST_STATEMENT_DETAIL
WHERE STATEMENT = #{id, jdbcType=BIGINT}

mapper.select:
SELECT DISTINCT TBC.ID, TBH.ID, TBC.CONTACT_NO, TBC.SETTLEMENT_BASIS_NAME SETTLEMENT_BASIS_NAME, TBC.OUTER_SETTLEMENT_BASIS_NAME OUTER_SETTLEMENT_BASIS_NAME, TBC.LUXIAO_SETTLEMENT_BASIS_NAME LUXIAO_SETTLEMENT_BASIS_NAME, TBC.EXP_SETTLEMENT_BASIS_NAME EXP_SETTLEMENT_BASIS_NAME, TBC.SIGN_TIME, TBC.CREATE_TIME FROM T_BUS_HANDOVERLIST TBH JOIN T_BUS_CARGO_INFO TBCI ON TBH.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBH.SHIPVOYAGE_ID = TDS.ID JOIN T_BUS_CONTRACT_COMPANY TBCC ON TBCI.COMPANY_ID = TBCC.COMPANY_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP ON TBH.CARGO_INFO_ID = TEMP.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP1 ON TBCI.ROOT_ID = TEMP1.CARGO_INFO_ID JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID AND TBH.CARGO_OWNER_ID = TBC.CUSTOMER_ID AND TO_DATE(TO_CHAR(CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE ( CASE WHEN TBCI.ROOT_ID IS NULL THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END) END, 'yyyy-MM-dd'), 'yyyy-MM-dd') >= TBC.START_TIME AND TO_DATE(TO_CHAR(CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE ( CASE WHEN TBCI.ROOT_ID IS NULL THEN TEMP.WEIGH_OUT_DT ELSE TBCI.TRANSFER_DATE END) END, 'yyyy-MM-dd'), 'yyyy-MM-dd') <= TBC.END_TIME ) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBC.ID = TBCR.CONTRACT_ID AND TBH.TRADE_TYPE = TBCR.TRADE_TYPE AND TBH.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM TBTI ON (TBCR.TRATE_ITEM_ID = TBTI.ID AND ( TBTI.TRADE_TYPE = '内/外贸' OR TBH.TRADE_TYPE = TBTI.TRADE_TYPE ) AND ( TBTI.IMP_EXP = '进/出口' OR DECODE(TBH.LOAD_UNLOAD, '卸', '进口', '装', '出口') = TBTI.IMP_EXP )) LEFT JOIN T_BUS_TRATE_ITEM_CARGO TBTIC ON (TBTI.ID = TBTIC.TRATE_ITEM_ID AND TBTIC.CARGO_CODE = TBCR.CARGO_CODE) LEFT JOIN T_BUS_TRATE_ITEM_DETAIL TBTID ON TBTI.ID = TBTID.TRATE_ITEM_ID
TBH.ID = #{id,jdbcType=BIGINT}
ORDER BY TBC.CREATE_TIME DESC
